  ('locality-d592fc58-moex-00204', 'locality-d592fc58', 'locality-d592fc58-moex-111-d3ff7f6b', 'sub-locality-d592fc58-02', NULL, 'single_choice', '長期下，若廠商選擇在長期平均成本線最低點生產，則我們稱之為生產效率（production', '["完全競爭市場", "寡占市場", "獨占 市場", "獨占性競爭市場"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:26+00:00", "source_pdf_sha1": "3f21c357b91c", "answer_pdf_sha1": "b1d8b4909cfe", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "321", "s": "1402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "商業行政"}'::jsonb, NULL),
